(function(){const RECENT_UPDATES_ENDPOINT='/recent_updates.json';let recentUpdatesRequestId=0;function isHomepagePath(urlLike=window.location){const pathname=typeof urlLike==='string'?new URL(urlLike,window.location.origin).pathname:urlLike.pathname;return pathname==='/'||pathname==='/index.html';}
function hideHomepageFirstElement(){const mdTypeset=document.querySelector('.md-typeset');const firstElement=mdTypeset?.firstElementChild;if(!firstElement){return;}
firstElement.style.display='none';}
function renderEmptyState(container,text){container.innerHTML=`<p class="recent-updates-empty">${text}</p>`;}
function loadRecentUpdates(container,options={}){if(!container){return;}
const requestId=++recentUpdatesRequestId;const requestUrl=options.forceRefresh?`${RECENT_UPDATES_ENDPOINT}?t=${Date.now()}`:RECENT_UPDATES_ENDPOINT;container.innerHTML=options.forceRefresh?'<p class="recent-updates-loading">正在刷新最近更新...</p>':'<p class="recent-updates-loading">正在加载最近更新...</p>';fetch(requestUrl).then((response)=>{if(!response.ok){throw new Error(`无法加载最近更新数据: ${response.status}`);}
return response.json();}).then((data)=>{if(requestId!==recentUpdatesRequestId){return;}
if(Array.isArray(data)&&data.length>0){renderRecentUpdates(container,data);return;}
renderEmptyState(container,'暂无最近更新');}).catch((error)=>{if(requestId!==recentUpdatesRequestId){return;}
console.warn('加载最近更新失败:',error);renderEmptyState(container,'最近更新暂时无法加载');});}
function initializeHomepageRecentUpdates(){if(!isHomepagePath()){return;}
hideHomepageFirstElement();const container=document.getElementById('recent-updates-container');if(!container){return;}
loadRecentUpdates(container);}
function renderRecentUpdates(container,updates){const html=`
            <ul class="recent-updates-list">
                ${updates.map(update => `<li class="recent-update-item"><div class="recent-update-content"><a href="${update.url}"class="recent-update-title">${update.title}</a>${update.nav_path?`<div class="recent-update-nav">${update.nav_path}</div>`:''}</div><div class="recent-update-date">${update.modified_str}</div></li>`).join('')}
            </ul>
        `;container.innerHTML=html;}
window.refreshRecentUpdates=function refreshRecentUpdates(){const container=document.getElementById('recent-updates-container');if(!container){return;}
loadRecentUpdates(container,{forceRefresh:true});};if(typeof document$!=='undefined'&&typeof document$.subscribe==='function'){document$.subscribe(()=>{initializeHomepageRecentUpdates();});}else if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',initializeHomepageRecentUpdates);}else{initializeHomepageRecentUpdates();}})();